import React, {
    FC,
    FunctionComponent,
    HTMLAttributeAnchorTarget,
    ReactNode,
    useEffect,
    useState
} from 'react';
import { eventBus } from '../../const';
import { pathJoin } from '../../tool';
import { Outlet, RouteObject, useLocation, useNavigate } from 'react-router-dom';
import KeepAlive, { KeepAliveProps } from 'react-activation';
interface TransparentLayoutProps {
    base: string;
    indexPath: string;
    children?: React.ReactNode | string;
}

//  {
//     DEFAULT = 'DEFAULT',
//     // 空白布局
//     BLANK = 'BLANK',
//     // 自定义布局
//     CUSTOM = 'CUSTOM',
// }

export const TransparentLayout: FC<TransparentLayoutProps> = ({ indexPath, base, children }) => {
    const location = useLocation();
    const navigate = useNavigate();

    useEffect(() => {
        if (location.pathname === base) {
            navigate(indexPath);
        }
        /* eslint-disable-next-line react-hooks/exhaustive-deps */
    }, [location.pathname, indexPath]);

    return children ? <div style={{ height: '100%' }}>{children}</div> : <Outlet />;
};

export interface SpotterRouteObject {
    caseSensitive?: boolean;
    // 只有存在 element ，在面包屑中展示时才会表现为链接
    element?: ReactNode;
    index?: boolean;
    path?: string;
    cache?: boolean;
    // 匹配到当前路由时会重定向到指定路径
    redirect?: string;
    /**
     * keepAlive 控制是否缓存当前页面，入参为 true 时缓存，false 时不缓存, 默认为 true
     */
    keepAlive?: boolean;
    keepAliveProps?: Omit<KeepAliveProps, 'cacheKey' | 'name'>;
    children?: SpotterRouteObject[];
    target?: HTMLAttributeAnchorTarget;
    // 国际化翻译所需要的唯一值
    i18nKey?: string;
    // 路由的唯一标识，目前主要用于 keep-alive 的缓存，不加key则自动使用路由绝对路径的pattern
    key?: string;
    name?: string;
    pageLayout?: React.ReactElement;
}

// 命名需要 key 和 value 相同
export enum GlobalLayoutType {
    // 默认的业务布局
    DEFAULT = 'DEFAULT',
    // 未登录场景使用的布局，包括所有未登录场景需要的路由
    AUTH = 'AUTH'
}

export class SpotterRouter {
    constructor(
        private options: {
            layout?: {
                [key in GlobalLayoutType]?: FunctionComponent;
            };
            guard?: {
                element?: FunctionComponent;
                downgradeRoutes?: SpotterRouteObject[];
            };
        }
    ) {}
    private static SPOTTER_ROUTE_CHANGE = 'SPOTTER_ROUTER_CHANGE';
    private layoutMap = {
        [GlobalLayoutType.DEFAULT]: {
            getLayoutRoute: (): RouteObject => ({
                element: this.options.guard?.element ? <this.options.guard.element /> : <Outlet />,
                children: [
                    {
                        element: this.options.layout?.DEFAULT ? (
                            <this.options.layout.DEFAULT />
                        ) : (
                            <Outlet />
                        ),
                        children: [
                            ...this.layoutMap[GlobalLayoutType.DEFAULT].pathRouteMap.values(),
                            ...(this.options.guard?.downgradeRoutes ?? [])
                        ] as RouteObject[]
                    }
                ]
            }),
            // 完整路径定义到 router 对象的映射
            pathRouteMap: new Map<string, SpotterRouteObject>()
        },
        [GlobalLayoutType.AUTH]: {
            getLayoutRoute: (): RouteObject => ({
                element: this.options.layout?.AUTH ? <this.options.layout.AUTH /> : <Outlet />,
                children: [
                    ...this.layoutMap[GlobalLayoutType.AUTH].pathRouteMap.values()
                ] as RouteObject[]
            }),
            pathRouteMap: new Map<string, SpotterRouteObject>()
        }
    };

    private generateRedirectLayout(route: SpotterRouteObject, parentPath = '') {
        const routeAbsolutePath = pathJoin(parentPath, route.path);
        if (route.redirect) {
            const redirectAbsolutePath = route.redirect.startsWith('/')
                ? route.redirect
                : pathJoin(routeAbsolutePath, route.redirect);
            route.element = (
                <TransparentLayout base={routeAbsolutePath} indexPath={redirectAbsolutePath}>
                    {route.element}
                </TransparentLayout>
            );
        }

        if (route.children?.length) {
            route.children = route.children.map((child) =>
                this.generateRedirectLayout(child, routeAbsolutePath)
            );
        }

        if (route.keepAlive) {
            const cacheName = route.key ?? routeAbsolutePath;
            route.element = (
                <KeepAlive cacheKey={cacheName} name={cacheName} {...route.keepAliveProps}>
                    {route.pageLayout ? (
                        React.cloneElement(route.pageLayout, {
                            children: route.element
                        })
                    ) : (
                        <div className='keep-alive-scroll-cache'>{route.element}</div>
                    )}
                </KeepAlive>
            );
        }

        return route;
    }

    onChange(handler: (newRoutes: RouteObject[]) => void) {
        eventBus.on(SpotterRouter.SPOTTER_ROUTE_CHANGE, handler as any);
    }

    offChange(handler: (newRoutes: RouteObject[]) => void) {
        eventBus.off(SpotterRouter.SPOTTER_ROUTE_CHANGE, handler as any);
    }

    /**
     * 当前路由会直接添加在指定的 Layout 路由下面
     * 举例来说，一级菜单需要添加在 DefaultLayout 下面
     */
    addLayoutRoute(route: SpotterRouteObject, layout = GlobalLayoutType.DEFAULT) {
        const { pathRouteMap } = this.layoutMap[layout];
        const routePath = route?.path ?? '';
        // 如果已经存在了路径定义，那么在控制台输出警告，然后用新的路由定义覆盖旧的定义
        pathRouteMap.has(routePath) &&
            console.warn(
                '⚠️存在重复的路由定义，新定义会覆盖旧定义：\n',
                '已有定义：',
                pathRouteMap.get(routePath),
                '新定义:',
                route
            );
        pathRouteMap.set(routePath, this.generateRedirectLayout(route));
        eventBus.emit(SpotterRouter.SPOTTER_ROUTE_CHANGE, this.getRoutes());
    }
    getRoutes(): RouteObject[] {
        return [
            ...Object.values(GlobalLayoutType).map((layout) =>
                this.layoutMap[layout as GlobalLayoutType].getLayoutRoute()
            )
        ];
    }
}

export const getUseSpotterRouters =
    (getSpotterRouter: () => SpotterRouter, initialRoutes = [] as RouteObject[]) =>
    () => {
        const [routes, setRoutes] = useState([...initialRoutes, ...getSpotterRouter().getRoutes()]);
        useEffect(() => {
            const handler = (newRoutes: RouteObject[]) => {
                setRoutes([...initialRoutes, ...newRoutes]);
            };
            getSpotterRouter().onChange(handler);
            return () => {
                getSpotterRouter().offChange(handler);
            };
        }, []);
        return routes;
    };
